import java.util.ArrayList;
import java.util.Scanner;

record Task(int id, String title, boolean done) {}

public class TaskTracker {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        ArrayList<Task> tasks = new ArrayList<>();
        int nextId = 1;

        while (true) {
            System.out.println("\n1. Add  2. List  3. Complete  4. Exit");
            System.out.print("Choice: ");
            int choice = Integer.parseInt(sc.nextLine().trim());

            switch (choice) {
                case 1 -> {
                    System.out.print("Task title: ");
                    tasks.add(new Task(nextId++, sc.nextLine(), false));
                    System.out.println("Added.");
                }
                case 2 -> {
                    if (tasks.isEmpty()) System.out.println("No tasks yet.");
                    else tasks.forEach(t ->
                        System.out.printf("%s #%d %s%n", t.done() ? "[x]" : "[ ]", t.id(), t.title()));
                }
                case 3 -> {
                    System.out.print("Task id: ");
                    int id = Integer.parseInt(sc.nextLine().trim());
                    tasks.replaceAll(t -> t.id() == id ? new Task(t.id(), t.title(), true) : t);
                    System.out.println("Marked complete.");
                }
                case 4 -> { sc.close(); return; }
                default -> System.out.println("Invalid choice.");
            }
        }
    }
}

