import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;

public class GitHubUserActivity {
    public static void main(String[] args) throws Exception {
        String username = args.length > 0 ? args[0] : "octocat";
        String url = "https://api.github.com/users/" + username + "/events/public";

        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create(url))
            .header("Accept", "application/vnd.github+json")
            .header("User-Agent", "Prathyu-Academy")
            .GET()
            .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        System.out.println("Status: " + response.statusCode());
        String body = response.body();
        int count = 0;
        int idx = 0;
        while ((idx = body.indexOf("\"type\":", idx)) != -1 && count < 5) {
            int start = body.indexOf('"', idx + 7) + 1;
            int end = body.indexOf('"', start);
            System.out.println("- " + body.substring(start, end));
            idx = end;
            count++;
        }
    }
}

expense-tracker-cli.code:
import java.util.ArrayList;
import java.util.Scanner;

record Expense(String desc, double amount, String category) {}

public class ExpenseTracker {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        ArrayList<Expense> expenses = new ArrayList<>();
        double total = 0;

        while (true) {
            System.out.println("\n1. Add expense  2. List  3. Exit");
            System.out.print("Choice: ");
            int c = Integer.parseInt(sc.nextLine().trim());
            if (c == 1) {
                System.out.print("Description: ");
                String desc = sc.nextLine();
                System.out.print("Amount: ");
                double amt = Double.parseDouble(sc.nextLine().trim());
                System.out.print("Category: ");
                String cat = sc.nextLine();
                expenses.add(new Expense(desc, amt, cat));
                total += amt;
                System.out.printf("Added. Total: Rs. %.2f%n", total);
            } else if (c == 2) {
                expenses.forEach(e -> System.out.printf("%-20s Rs.%8.2f [%s]%n", e.desc(), e.amount(), e.category()));
                System.out.printf("Total: Rs. %.2f%n", total);
            } else if (c == 3) {
                sc.close();
                return;
            }
        }
    }
}

