import java.util.Scanner;

public class UnitConverter {
    static double toMeters(double val, String unit) {
        return switch (unit.toLowerCase()) {
            case "km" -> val * 1000;
            case "mi" -> val * 1609.344;
            case "ft" -> val * 0.3048;
            default -> val;
        };
    }

    static double fromMeters(double m, String unit) {
        return switch (unit.toLowerCase()) {
            case "km" -> m / 1000;
            case "mi" -> m / 1609.344;
            case "ft" -> m / 0.3048;
            default -> m;
        };
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        System.out.print("Value: ");
        double val = sc.nextDouble();
        sc.nextLine();
        System.out.print("From unit (m/km/mi/ft): ");
        String from = sc.nextLine().trim();
        System.out.print("To unit (m/km/mi/ft): ");
        String to = sc.nextLine().trim();
        double result = fromMeters(toMeters(val, from), to);
        System.out.printf("%.4f %s = %.4f %s%n", val, from, result, to);
        sc.close();
    }
}

