import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.HashMap;
import java.util.Map;

public class CachingProxy {
    record CacheEntry(String body, long time) {}

    static final Map<String, CacheEntry> CACHE = new HashMap<>();
    static final long TTL_MS = 60_000;

    static String fetch(String url) throws Exception {
        CacheEntry hit = CACHE.get(url);
        if (hit != null && System.currentTimeMillis() - hit.time() < TTL_MS) {
            System.out.println("CACHE HIT");
            return hit.body();
        }
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest req = HttpRequest.newBuilder().uri(URI.create(url)).GET().build();
        String body = client.send(req, HttpResponse.BodyHandlers.ofString()).body();
        CACHE.put(url, new CacheEntry(body, System.currentTimeMillis()));
        System.out.println("CACHE MISS");
        return body;
    }

    public static void main(String[] args) throws Exception {
        String url = "https://api.github.com/zen";
        System.out.println(fetch(url).substring(0, Math.min(80, fetch(url).length())));
        System.out.println(fetch(url).substring(0, Math.min(80, fetch(url).length())));
    }
}

