import java.io.File;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class DatabaseBackupUtility {
    public static void main(String[] args) throws Exception {
        String db = args.length > 0 ? args[0] : "mydb";
        String user = args.length > 1 ? args[1] : "root";
        String dir = "backups";
        new File(dir).mkdirs();
        String file = dir + "/backup-" + LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyyMMdd-HHmmss")) + ".sql";

        ProcessBuilder pb = new ProcessBuilder("mysqldump", "-u", user, db);
        pb.redirectOutput(new File(file));
        Process p = pb.start();
        int code = p.waitFor();
        System.out.println(code == 0 ? "Backup saved: " + file : "Backup failed with code " + code);
    }
}
